def searchRange(nums, target):
    def find(left):
        l, r, res = 0, len(nums)-1, -1
        while l <= r:
            m = (l+r)//2
            if nums[m] == target:
                res = m
                if left: r = m-1
                else: l = m+1
            elif nums[m] < target: l = m+1
            else: r = m-1
        return res
    return [find(True), find(False)]

